// Runs is the resolver for the runs field.
func (r *eventV2Resolver) Runs(ctx context.Context, obj *models.EventV2) ([]*models.FunctionRunV2, error) {
	// convert cqrs TraceRun to FunctionRunV2

	// This is an N+1, currently also an N+1 on cloud in the form of multiple calls to the metrics service
	// we cannot currently use a data loader due to current db schema and https://github.com/sqlc-dev/sqlc/issues/1830
	traceRuns, err := r.Data.GetTraceRunsByTriggerID(ctx, obj.ID)
	if err != nil {
		return nil, err
	}

	functionRuns := make([]*models.FunctionRunV2, 0, len(traceRuns))
	for _, r := range traceRuns {
		// TODO dedupe cqrs.TraceRun to models.FunctionRunV2 transformation
		var (
			started   *time.Time
			ended     *time.Time
			sourceID  *string
			output    *string
			batchTime *time.Time
		)

		if r.StartedAt.UnixMilli() > 0 {
			started = &r.StartedAt
		}
		if r.EndedAt.UnixMilli() > 0 {
			ended = &r.EndedAt
		}
		if len(r.SourceID) > 0 {
			sourceID = &r.SourceID
		}
		if len(r.Output) > 0 {
			s := string(r.Output)
			output = &s
		}
		runID := ulid.MustParse(r.RunID)
		status, err := models.ToFunctionRunStatus(r.Status)
		if err != nil {
			continue
		}

		functionRuns = append(functionRuns, &models.FunctionRunV2{
			ID:             runID,
			AppID:          r.AppID,
			FunctionID:     r.FunctionID,
			TraceID:        r.TraceID,
			QueuedAt:       r.QueuedAt,
			StartedAt:      started,
			EndedAt:        ended,
			SourceID:       sourceID,
			Status:         status,
			Output:         output,
			IsBatch:        r.IsBatch,
			BatchCreatedAt: batchTime,
			CronSchedule:   r.CronSchedule,
			HasAi:          r.HasAI,
		})
	}
	return functionRuns, nil
}

// TotalCount is the resolver for the totalCount field.
func (r *eventsConnectionResolver) TotalCount(ctx context.Context, obj *models.EventsConnection) (int, error) {
	filter := graphql.GetFieldContext(ctx).Parent.Args["filter"].(models.EventsFilter)

	opts := cqrs.WorkspaceEventsOpts{
		Limit:                 cqrs.MaxEvents, // pass in dummy value to pass validation, but won't be used in actual count query
		Names:                 filter.EventNames,
		IncludeInternalEvents: filter.IncludeInternalEvents,
		Oldest:                filter.From,
	}

	// this relies on the frontend not requesting TotalCount except on loading the first page
	opts.Newest = time.Now()
	if filter.Until != nil {
		opts.Newest = *filter.Until
	}

	totalCount, err := r.Data.GetEventsCount(ctx, consts.DevServerAccountID, consts.DevServerEnvID, opts)

	if err != nil {
		return 0, err
	}
	return int(totalCount), nil
}

