// InBatch is the resolver for the inBatch field.
func (r *streamItemResolver) InBatch(ctx context.Context, obj *models.StreamItem) (bool, error) {
	eventID, err := ulid.Parse(obj.ID)
	if err != nil {
		return false, err
	}

	batches, err := r.Data.GetEventBatchesByEventID(ctx, eventID)
	if err != nil {
		return false, err
	}

	return len(batches) > 0, nil
}

